interviewQuestions.answer:
Method borrowing is taking a method from one object and using it on another object with call(): <code>const arrLike = { 0: 'a', 1: 'b', length: 2 };
const arr = Array.prototype.slice.call(arrLike, 0);
console.log(arr); // ['a', 'b']</code>

In constructor functions, call() is used to invoke a parent constructor on the current instance: <code>function Parent(name) { this.name = name; }
function Child(name, age) {
  Parent.call(this, name); // Parent runs on Child instance
  this.age = age;
}
const c = new Child('Alice', 10);
console.log(c.name); // 'Alice'</code>

codeExamples.code:
const alice = { name: 'Alice' };
const bob   = { name: 'Bob' };

function greet(greeting) {
  return `${greeting}, ${this.name}!`;
}

console.log(greet.call(alice, 'Hello')); // 'Hello, Alice!'
console.log(greet.call(bob, 'Hi'));      // 'Hi, Bob!'

// Without call() — this is undefined/global:
// console.log(greet('Hello')); // 'Hello, undefined!' or error

function sum() {
  // 'arguments' is array-like, not a real array
  // We borrow slice from Array.prototype
  const args = Array.prototype.slice.call(arguments, 0);

  // Now args is a real array with all array methods
  return args.reduce((total, n) => total + n, 0);
}

console.log(sum(1, 2, 3, 4, 5)); // 15

// Also works with NodeLists and HTMLCollections:
// const divs = document.querySelectorAll('div');
// const divArray = Array.prototype.slice.call(divs);

function Animal(type) {
  this.type = type;
  this.isAlive = true;
}

function Dog(name, breed) {
  // Call parent constructor on 'this' instance
  Animal.call(this, 'mammal');

  this.name = name;
  this.breed = breed;
}

const dog = new Dog('Buddy', 'Golden Retriever');
console.log(dog.type);    // 'mammal' (set by Animal.call)
console.log(dog.name);    // 'Buddy'
console.log(dog.isAlive); // true

function getType(value) {
  return Object.prototype.toString.call(value).slice(8, -1);
}

console.log(getType([]));           // 'Array'
console.log(getType({}));           // 'Object'
console.log(getType('hello'));      // 'String'
console.log(getType(42));           // 'Number'
console.log(getType(null));         // 'Null'
console.log(getType(undefined));    // 'Undefined'
console.log(getType(function(){})); // 'Function'
console.log(getType(new Date()));   // 'Date'

// More reliable than typeof:
// typeof []        → 'object' (wrong)
// typeof null      → 'object' (wrong!)

const customObj = {
  0: 10,
  1: 20,
  2: 30,
  length: 3
};

// Borrow Math.max on array-like object
const maxVal = Math.max.call(null, ...Array.from(customObj));
console.log(maxVal); // 30

// More practically: borrow .push on array-like
const arrLike = { 0: 'a', 1: 'b', length: 2 };
Array.prototype.push.call(arrLike, 'c');
console.log(arrLike); // { 0: 'a', 1: 'b', 2: 'c', length: 3 }

